1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = {
13	  type: string;
14	  material?: string;
15	  enchantment?: number;
16	  cursed?: boolean;
17	};
18	type Step = { op: "quote"; items: Item[] };
19	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	const BLOCK_SIZE = 3;
23	const BLOCK_BASE_PREMIUM = 60;
24	
25	const itemPremium = (item: Item): number => {
26	  const basePremium = BASE_PREMIUM_BY_TYPE[item.type];
27	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
28	  return basePremium + firstInsuranceSurcharge;
29	};
30	
31	const componentGroupBasePremium = (type: string, count: number): number => {
32	  if (count === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
33	  return count * BASE_PREMIUM_BY_TYPE[type];
34	};
35	
36	const quotePremium = (items: Item[]): number => {
37	  const componentItems = items.filter((item) => COMPONENT_TYPES.has(item.type));
38	  const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
39	
40	  const mainTotal = mainItems.reduce((sum, item) => sum + itemPremium(item), 0);
41	
42	  const countsByType = componentItems.reduce<Record<string, number>>((acc, item) => {
43	    acc[item.type] = (acc[item.type] ?? 0) + 1;
44	    return acc;
45	  }, {});
46	
47	  const componentBaseTotal = Object.entries(countsByType).reduce(
48	    (sum, [type, count]) => sum + componentGroupBasePremium(type, count),
49	    0,
50	  );
51	  const componentTotal = componentBaseTotal + componentBaseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
52	
53	  return mainTotal + componentTotal + PROCESSING_FEE;
54	};
55	
56	type QuoteResult = { premium: number };
57	
58	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
59	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
60	  return { results };
61	};
